import Detail from "./Detail.vue";
import { exportRowsToExcel } from "../../utils/excel";
export default {
  components: {
    Detail: Detail
  },
  data: function data() {
    return {
      form: {
        name: "",
        phone: "",
        pageNo: 1,
        pageSize: 5
      },
      users: [],
      total: 0
    };
  },
  methods: {
    handleSizeChange: function handleSizeChange(val) {
      this.form.pageSize = val;
      this.form.pageNo = 1;
      this.searchUser();
    },
    handleCurrentChange: function handleCurrentChange(val) {
      this.form.pageNo = val;
      this.searchUser();
    },
    updateUser: function updateUser(id) {
      this.$refs.update.form.id = id;
      this.$refs.update.dialogVisible = true;
      this.$refs.update.findUserById(id);
    },
    viewDetail: function viewDetail(id) {
      this.$refs.detail.dialogVisible = true;
      this.$refs.detail.loadUserDetail(id);
    },
    resetPassword: function resetPassword(id) {
      var _this = this;

      this.$confirm('此操作将重置该用户密码, 是否继续?', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(function () {
        _this.$http.post("/api/userCtl/reset", "id=" + id).then(function (resp) {
          console.log(resp.data);
        });

        _this.$message({
          type: 'success',
          message: '重置成功!',
          duration: 1000
        });
      }).catch(function () {
        _this.$message({
          type: 'info',
          message: '已取消重置',
          duration: 1000
        });
      });
    },
    searchUser: function searchUser() {
      var _this2 = this;

      this.$http.post("/api/userCtl/sendList", this.form).then(function (resp) {
        _this2.users = resp.data.data.list;
        _this2.total = resp.data.data.total;

        if (resp.data.data.size == 0) {
          _this2.$message({
            message: '未查询到该用户!',
            type: 'warning',
            duration: 1000
          });
        }
      });
    },
    exportExcel: function exportExcel() {
      if (!this.users || this.users.length === 0) {
        this.$message.warning('暂无可导出的配送员数据');
        return;
      }

      var rows = [['姓名', '性别', '年龄', '手机号', '地址', '社区']];
      this.users.forEach(function (item) {
        rows.push([item.name || '', item.gender || '', item.age || '', item.phone || '', item.address || '', item.community ? item.community.name : '-']);
      });
      exportRowsToExcel('配送员列表', rows);
    },
    deleteUser: function deleteUser(id) {
      var _this3 = this;

      this.$confirm('此操作将永久删除该用户, 是否继续?', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(function () {
        _this3.$http.get("/api/userCtl/deleteUser?id=" + id).then(function (resp) {
          console.log(resp.data);

          _this3.$message({
            type: 'success',
            message: '删除成功!',
            duration: 1000
          }); // 刷新列表


          _this3.searchUser();
        }).catch(function (error) {
          console.error('删除失败:', error);

          _this3.$message({
            type: 'error',
            message: '删除失败，请重试',
            duration: 2000
          });
        });
      }).catch(function () {
        _this3.$message({
          type: 'info',
          message: '已取消删除',
          duration: 1000
        });
      });
    }
  },
  mounted: function mounted() {
    this.searchUser();
  }
};
